-- create "replenishment_orders" table
CREATE TABLE "replenishment_orders" ("id" uuid NOT NULL, "tenant_id" uuid NOT NULL, "data_type_id" uuid NULL, "data_type_slug" character varying NULL, "data" jsonb NULL, "created_at" timestamptz NOT NULL, "created_by" uuid NULL, "updated_at" timestamptz NULL, "updated_by" uuid NULL, "deleted_at" timestamptz NULL, "deleted_by" uuid NULL, "supplier_id" uuid NOT NULL, "status" character varying NOT NULL DEFAULT 'pending', "expected_delivery_date" timestamptz NULL, "priority" character varying NOT NULL DEFAULT 'medium', PRIMARY KEY ("id"));
-- create "replenishment_order_items" table
CREATE TABLE "replenishment_order_items" ("id" uuid NOT NULL, "tenant_id" uuid NOT NULL, "data_type_id" uuid NULL, "data_type_slug" character varying NULL, "data" jsonb NULL, "created_at" timestamptz NOT NULL, "created_by" uuid NULL, "updated_at" timestamptz NULL, "updated_by" uuid NULL, "deleted_at" timestamptz NULL, "deleted_by" uuid NULL, "sku" character varying NOT NULL, "quantity_requested" bigint NOT NULL, "quantity_approved" bigint NULL, "unit_cost" double precision NULL, "replenishment_order_id" uuid NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "replenishment_order_items_replenishment_orders_replenishmentOrderItems" FOREIGN KEY ("replenishment_order_id") REFERENCES "replenishment_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);